solutions.cpp:
#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    int solve(vector<int>& nums) {
        int count = 0;
        for (int i = 0; i < nums.size(); i++)
            count++;
        return count;
    }
};

int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++)
        cin >> nums[i];
    cout << Solution().solve(nums) << endl;
    return 0;
}
